#[test]
fn map_wallet_event_transaction_instant_locked_emits_balance() {
    let balance = WalletCoreBalance::new(99_000, 1_000, 0, 0);
    let event = WalletEvent::TransactionInstantLocked {
        wallet_id: [0; 32],
        txid: Txid::all_zeros(),
        balance: balance.clone(),
        account_balances: Default::default(),
    };
    let mapped = map_wallet_event(event, Network::Mainnet);
    assert_eq!(mapped.len(), 1);
    assert_eq!(mapped[0], SpvEvent::BalanceUpdated(balance));
}

#[test]
fn map_wallet_event_block_processed_with_records_emits_transaction_and_balance() {
    let tx = Transaction::dummy_empty();
    let record = make_record(tx, TransactionContext::Mempool, vec![], vec![], 1_000);
    let balance = WalletCoreBalance::new(1_000, 0, 0, 0);
    let event = WalletEvent::BlockProcessed {
        wallet_id: [0; 32],
        height: 500,
        inserted: vec![record],
        updated: vec![],
        matured: vec![],
        balance: balance.clone(),
        account_balances: Default::default(),
        addresses_derived: vec![],
    };
    let mapped = map_wallet_event(event, Network::Mainnet);
    assert_eq!(mapped.len(), 2);
    assert!(matches!(mapped[0], SpvEvent::TransactionReceived(_)));
    assert_eq!(mapped[1], SpvEvent::BalanceUpdated(balance));
}

#[test]
fn ffi_balance_to_core_maps_all_fields() {
    use key_wallet_ffi::types::FFIBalance;
    let b = FFIBalance { confirmed: 100, unconfirmed: 50, immature: 25, locked: 10 };
    let result = ffi_balance_to_core(&b);
    assert_eq!(result, WalletCoreBalance::new(100, 50, 25, 10));
}
